options.systemMessage:
=# MISIÓN
Responder preguntas de clientes como un vendedor experto de MercadoLibre.
Responder de forma natural, profesional y en el idioma de la pregunta. Si no tienes la información específica, usa tu mejor juicio para responder.

# REGLAS CRÍTICAS
1. PROHIBIDO dar información de contacto: nombre real de la empresa (fuera de la firma), email, teléfono o ubicación física.
2. No respondas con el nombre del producto incluido en la respuesta si no es estrictamente necesario.
3. Responde con frases profesionales que induzcan a la venta.
4. Deduce de qué país es la pregunta en base a los datos de la publicación y responde con expresiones propias de ese país (ej: Argentina, México, Uruguay, etc).
5. SIEMPRE responde en el MISMO IDIOMA en que te hicieron la pregunta.
6. Si las instrucciones del vendedor o el saludo están en un idioma diferente al de la pregunta, TRADÚCELOS al idioma de la pregunta manteniendo el tono.

# CONOCIMIENTO DEL PRODUCTO (CONTEXTO TÉCNICO)
{{ $('context:assembler').item.json.ai_payload.full_context }}

# INSTRUCCIONES PARTICULARES DEL VENDEDOR
- Precio: {{ $('context:assembler').item.json.ai_payload.user_prompts.precio }}
- Medios de Pago: {{ $('context:assembler').item.json.ai_payload.user_prompts.mediosPago }}
- Garantía: {{ $('context:assembler').item.json.ai_payload.user_prompts.garantia }}
- Envíos (tipo: {{ $('context:assembler').item.json.ai_payload.shipping_type }}): {{ $('context:assembler').item.json.ai_payload.resolved_shipping }}
- Condición: {{ $('context:assembler').item.json.ai_payload.user_prompts.condicionProducto }}
- Instrucciones Adicionales: {{ $('context:assembler').item.json.ai_payload.user_prompts.otros }}

# SALUDO Y CIERRE
{{ $('context:assembler').item.json.ai_payload.resolved_greeting ? 'Al final de tu respuesta, incluye este saludo: "' + $('context:assembler').item.json.ai_payload.resolved_greeting + '". Si está en un idioma diferente al de la pregunta, tradúcelo naturalmente.' : 'Termina con un saludo comercial breve y profesional en el idioma del cliente.' }}

parameters.jsCode:
function getSafeData(nodeName) {
  try {
    return $(nodeName).first().json;
  } catch (e) {
    return null;
  }
}

const item = getSafeData("get_item_details");
const accountDetails = getSafeData("get_account_details");
const itemDescNode = getSafeData("get_item_description");
const catalogDescNode = getSafeData("get_catalog_description");
const catalogDetailsNode = getSafeData("get_relationship_item_description");
const questionDetails = getSafeData("get_queston_details");
const ragNode = getSafeData("rag_search");

const price = item.price;
const originalPrice = item.original_price;
const hasOffer = originalPrice && originalPrice > price;

// --- EXTRACCIÓN DE DATOS ADICIONALES ---
// Buscamos el SKU en los atributos
const sku = item.attributes?.find(a => a.id === 'SELLER_SKU')?.value_name || 'No definido';
// Obtenemos una imagen de alta resolución (la primera de la galería)
const bigImage = item.pictures && item.pictures.length > 0 ? item.pictures[0].secure_url : item.thumbnail;
// Formateamos la condición
const condition = item.condition === 'new' ? 'Nuevo' : (item.condition === 'used' ? 'Usado' : item.condition);

const prompts = accountDetails?.prompts || {};
// Resolución de saludo por tienda (fallback → saludoGeneral)
const officialStoreId  = item.official_store_id?.toString();
const storeGreetings   = accountDetails?.store_greetings || {};
const resolvedGreeting = (officialStoreId && storeGreetings[officialStoreId])
                         || prompts?.saludoGeneral
                         || '';
// --- DETECCIÓN Y RESOLUCIÓN DE TIPO DE ENVÍO ---
const shipping     = item.shipping || {};
const logisticType = shipping.logistic_type || '';
const shippingMode = shipping.mode || '';
const localPickup  = shipping.local_pick_up === true;
const shippingTags = shipping.tags || [];

let shippingKey;

// 1. Fulfillment siempre gana (logistic_type es definitivo)
if      (logisticType === 'fulfillment') {
  shippingKey = 'fulfillment';
}
// 2. Flex (por tags, independiente del mode)
else if (shippingTags.includes('self_service_in') || shippingTags.includes('flex')) {
  shippingKey = 'flex';
}
// 3. mode es el campo más confiable para me1/me2 (drop_off aplica a ambos)
else if (shippingMode === 'me2' || logisticType === 'cross_docking') {
  shippingKey = 'me2';
}
else if (shippingMode === 'me1' || logisticType === 'xd_drop_off') {
  shippingKey = 'me1';
}
// 4. drop_off sin mode explícito → me1
else if (logisticType === 'drop_off') {
  shippingKey = 'me1';
}
// 5. Retiro en local
else if (localPickup || logisticType === 'not_specified') {
  shippingKey = 'pickup';
}
// 6. Personalizado / self_service / custom
else {
  shippingKey = 'custom';
}

const shippingInstructions = accountDetails?.shipping_instructions || {};
const resolvedShipping     = shippingInstructions[shippingKey]
                             || prompts?.envios
                             || '';
const itemDesc = itemDescNode?.plain_text || "";
const catalogDesc = catalogDescNode?.plain_text || "";
const ragContext = ragNode?.context || "";

// Contexto para la IA
let contextData = `--- INFORMACIÓN DEL PRODUCTO ---
Título: ${item.title}
ID MeLi: ${item.id}
SKU: ${sku}
Precio: ${item.currency_id} ${item.price}
Stock: ${item.available_quantity}
Atributos: ${item.attributes ? item.attributes.map(a => `${a.name}: ${a.value_name}`).join(', ') : 'N/A'}\n`;

if (catalogDetailsNode) {
  contextData += `--- FICHA TÉCNICA EXTRA ---\n${catalogDetailsNode.attributes?.map(a => `${a.name}: ${a.value_name}`).join('\n')}\n`;
}

// --- DISEÑO DE LA "CARD" PARA CHATWOOT ---
// Usamos blockquotes (>) para dar efecto de contenedor/card
const productNote = `
### 📦 DETALLES DEL PRODUCTO
> [![${item.title}](${bigImage})](${item.permalink})
> 
> **[${item.title}](${item.permalink})**
>
> 🆔 **ID MeLi:** \`${item.id}\` | 🔢 **SKU:** \`${sku}\`
> 💰 **Precio:** ${item.currency_id} ${price.toLocaleString()} ${hasOffer ? `(🔥 ~~${item.currency_id} ${originalPrice.toLocaleString()}~~)` : ''}
> 📦 **Stock:** ${item.available_quantity} unidades | 📈 **Ventas:** ${item.sold_quantity}
> 🛠️ **Estado:** ${condition} | 📂 **Categoría:** ${item.category_id}
> 🔗 **Garantía:** ${item.warranty || 'No especificada'}
---
`.trim();

return {
  ai_payload: {
    question: questionDetails?.text || "Pregunta no encontrada",
    full_context: contextData
      + "\n--- DESCRIPCIÓN ---\n" + itemDesc + "\n" + catalogDesc
      + (ragContext ? "\n--- BASE DE CONOCIMIENTO ---\n" + ragContext : ""),
    user_prompts: prompts,
    delay: accountDetails?.delay || { seconds: 30 },
    chatwoot_account_id: accountDetails?.chatwoot_account_id,
    product_note_markdown: productNote,
    access_token: accountDetails?.access_token,
    resolved_greeting:  resolvedGreeting,
    resolved_shipping:  resolvedShipping,
    shipping_type:      shippingKey,
  }
};
